/**
 * Bootstrap-compatible class map.
 * Does not depend on Bootstrap — use these classes when Bootstrap is already on the page.
 * `d-block` ensures the feedback element is visible when injected next to the field.
 */
export const bootstrapPreset = {
  fieldContainer: '.mb-3',
  errorClass: 'is-invalid',
  errorMessageClass: 'invalid-feedback d-block',
  errorElement: 'div',
};
